import type { HTMLAttributes } from 'react';
type ProgressType = 'container' | 'solo';
export type CircleSize = 'standart' | 'mini';
export interface ProgressProps extends HTMLAttributes<HTMLDivElement> {
    /** Значение (в процентном отношении от 0 до 100) */
    value?: number;
    /** Форма компонента, линейный / круговой / анимационный */
    shape?: 'linear' | 'circle' | 'animated';
    /**
     * @deprecated больше не используется
     * Ширина полоски, устарело у элементов стандартная ширина
     */
    strokeWidth?: number;
    /**
     * @deprecated Изменено значение
     *  Размер компонента для типа circle, теперь у элемента 2 стандартных размера standart / mini
     */
    size?: number | CircleSize;
    /** Признак анимации вкл / выкл */
    cycled?: boolean;
    /** Тип линейного прогресса (с закруглением боковых сторон / без) */
    type?: ProgressType;
    /** Пользовательский класс*/
    className?: string;
}
export {};
